# playbook_batch.py
# Route classification / enrichment workloads to the Batch API.

import anthropic
import json
import time
from pathlib import Path

client = anthropic.Anthropic()

def build_batch_requests(items: list[dict], system_prompt: str) -> list[dict]:
    """
    Convert a list of items into Batch API request objects.
    Each item must have a unique 'id' and a 'text' field.
    """
    return [
        {
            "custom_id": item["id"],
            "params": {
                "model": "claude-haiku-4-5-20251001",
                "max_tokens": 256,
                "system": system_prompt,
                "messages": [
                    {"role": "user", "content": item["text"]}
                ],
            },
        }
        for item in items
    ]

def submit_and_collect(
    requests: list[dict],
    poll_interval_s: int = 60,
    timeout_s: int = 86_400,
) -> list[dict]:
    """Submit a batch, poll until done, return results indexed by custom_id."""
    batch = client.messages.batches.create(requests=requests)
    print(f"Batch {batch.id} submitted — {len(requests)} requests")

    deadline = time.time() + timeout_s
    while time.time() < deadline:
        batch = client.messages.batches.retrieve(batch.id)
        counts = batch.request_counts
        print(
            f"  processing={counts.processing} "
            f"succeeded={counts.succeeded} "
            f"errored={counts.errored} "
            f"canceled={counts.canceled}"
        )
        if batch.processing_status == "ended":
            break
        time.sleep(poll_interval_s)

    results: dict[str, dict] = {}
    for result in client.messages.batches.results(batch.id):
        if result.result.type == "succeeded":
            results[result.custom_id] = {
                "text": result.result.message.content[0].text,
                "usage": {
                    "input_tokens": result.result.message.usage.input_tokens,
                    "output_tokens": result.result.message.usage.output_tokens,
                },
            }
        else:
            results[result.custom_id] = {
                "error": result.result.error.type if hasattr(result.result, "error") else "unknown"
            }
    return results

# Example: batch classify 500 support tickets overnight
CLASSIFY_SYSTEM = (
    "Classify the support ticket into exactly one category: "
    "billing | technical | account | feature_request | other. "
    "Reply with only the category label."
)

def classify_tickets(tickets: list[dict]) -> dict[str, str]:
    """tickets: list of {id, text}. Returns {id: category}."""
    CHUNK = 9_000  # stay under 10k limit with margin
    categories: dict[str, str] = {}
    for i in range(0, len(tickets), CHUNK):
        chunk = tickets[i : i + CHUNK]
        reqs = build_batch_requests(chunk, CLASSIFY_SYSTEM)
        results = submit_and_collect(reqs)
        for cid, res in results.items():
            categories[cid] = res.get("text", "error").strip()
        print(f"Classified {min(i+CHUNK, len(tickets))}/{len(tickets)} tickets")
    return categories

# playbook_combined.py
# Combine caching + batch for maximum savings on document enrichment.
# Use case: nightly enrichment of 10k product descriptions.

import anthropic
import json, time

client = anthropic.Anthropic()

# This system prompt is identical for all requests — it will be cached
# after the first request in the batch (shared cache within a batch).
ENRICH_SYSTEM = """You are a product data enrichment engine. Your output is always valid JSON.

## Category taxonomy
[... 2000 tokens of category definitions, synonym maps, attribute schemas ...]

## Output schema
{
  "categories": ["string"],
  "attributes": {"key": "value"},
  "seo_title": "string",
  "search_tags": ["string"]
}

Output ONLY the JSON object, no other text.
"""

def enrich_products_batch(products: list[dict]) -> dict[str, dict]:
    """
    Enrich product descriptions overnight using Batch API.
    Each request includes the same system prompt — the API caches it
    automatically when it detects identical prefix content in the batch.
    """
    requests = []
    for product in products:
        requests.append({
            "custom_id": product["sku"],
            "params": {
                "model": "claude-haiku-4-5-20251001",
                "max_tokens": 512,
                "system": [
                    {
                        "type": "text",
                        "text": ENRICH_SYSTEM,
                        "cache_control": {"type": "ephemeral"},
                    }
                ],
                "messages": [
                    {
                        "role": "user",
                        "content": f"Product: {product['name']}\nDescription: {product['description']}",
                    }
                ],
            },
        })

    batch = client.messages.batches.create(requests=requests)
    print(f"Batch {batch.id}: {len(requests)} products queued")

    while True:
        batch = client.messages.batches.retrieve(batch.id)
        if batch.processing_status == "ended":
            break
        time.sleep(120)

    enriched: dict[str, dict] = {}
    for result in client.messages.batches.results(batch.id):
        if result.result.type == "succeeded":
            try:
                data = json.loads(result.result.message.content[0].text)
                enriched[result.custom_id] = data
            except json.JSONDecodeError:
                enriched[result.custom_id] = {"error": "parse_failure"}
    return enriched
